cypher:
MATCH (u:User)
            WHERE EXISTS { MATCH (u)-[:MEMBER_OF]->(g:Group) WHERE g.name = 'Engineering' }
            RETURN u.name

MATCH (a:User)
        WHERE EXISTS {
            MATCH (a)-[:AUTHORED]->(p)
        }
        RETURN count(*) as total

MATCH (ip)-[:REQUESTED]->(d:Domain)
        WHERE EXISTS {
            MATCH (ip)-[:ACCESSED]->(dest)
        }
        RETURN count(*) as total
